using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// Train the model and save to disk
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
TrainModel(
    Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv"),
    modelPath);

// Register the pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with Age, Income, Region, PurchaseHistory");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        Churned = prediction.Churned,
        Probability = prediction.Probability,
    });
});

app.Run();

static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    IDataView data = mlContext.Data.LoadFromTextFile<CustomerData>(
        dataPath, hasHeader: true, separatorChar: ',',
        allowQuoting: true, trimWhitespace: true);

    // Map "Yes"/"No" label to bool
    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
        .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

    var model = pipeline.Fit(split.TrainSet);

    // Evaluate on the held-out test set
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

