static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    IDataView data = mlContext.Data.LoadFromTextFile<CustomerData>(
        dataPath, hasHeader: true, separatorChar: ',',
        allowQuoting: true, trimWhitespace: true);

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    // Map "Yes"/"No" to a boolean Label column
    var labelKeys = new[] { "Yes".AsMemory(), "No".AsMemory() };
